external_knowledge:
- On-time flights refer to flights that depart at the scheduled time or earlier; 
- Fully operational aircraft refers to those that are under no maintenance and are ready to operate; 
- Average departure delay refers to the mean delay time of flights that departed late.

sql:
SELECT flight_no
FROM flights
ORDER BY flight_no ASC;

SELECT DISTINCT fs.flight_id
FROM flight_status fs
WHERE fs.status IN ('Delayed', 'Cancelled');

SELECT COUNT(*) AS passenger_count
FROM passenger_manifest
WHERE flight_id = 1;

SELECT flight_no
FROM flights
ORDER BY flight_no;

